#include <comp421/yalnix.h>
#include <comp421/iolib.h>
#include <comp421/filesystem.h>
#include <stdlib.h>
#include <string.h>

#define MSG_OPEN        1
#define MSG_CLOSE       2
#define MSG_CREATE      3
#define MSG_READ        4
#define MSG_WRITE       5
#define MSG_SEEK        6
#define MSG_LINK        7
#define MSG_UNLINK      8
#define MSG_SYMLINK     9
#define MSG_READLINK    10
#define MSG_MKDIR       11
#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

struct message {
    int type;
    int cwd_inum;
    int inum;
    int reuse;
    int position;
    int size;
    void *ptr1;
    int int1;
};

struct reply {
    int result;
    int inum;
    int reuse;
    int stat_type;
    int stat_size;
};

struct fd_info {
    int inum;
    int reuse;
    int position;
    int in_use;
};

static struct fd_info fd_table[MAX_OPEN_FILES];
static int cwd_inum = ROOTINODE;
static int lib_initialized = 0;

static void init_lib(void) {
    if (lib_initialized) return;
    lib_initialized = 1;
}

static int find_fd(void) {
    int i;
    for (i = 0; i < MAX_OPEN_FILES; i++) {
        if (!fd_table[i].in_use) return i;
    }
    return ERROR;
}

int Open(char *pathname)
{
    init_lib();
    (void)pathname;
    return ERROR;
}

int Close(int fd)
{
    init_lib();
    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use) return ERROR;
    fd_table[fd].in_use = 0;
    return 0;
}

int Create(char *pathname)
{
    struct message msg;
    struct reply reply;
    int pathname_len;
    int fd_num;

    init_lib();

    if (!pathname) return ERROR;
    pathname_len = strlen(pathname) + 1;
    if (pathname_len > MAXPATHNAMELEN) return ERROR;

    msg.type = MSG_CREATE;
    msg.cwd_inum = cwd_inum;
    msg.ptr1 = (void *)pathname;
    msg.int1 = pathname_len;

    if (Send(&msg, -FILE_SERVER) < 0) return ERROR;
    if (Receive(&reply) < 0) return ERROR;

    if (reply.result < 0) return ERROR;

    fd_num = find_fd();
    if (fd_num < 0) return ERROR;

    fd_table[fd_num].inum = reply.inum;
    fd_table[fd_num].reuse = reply.reuse;
    fd_table[fd_num].position = 0;
    fd_table[fd_num].in_use = 1;

    return fd_num;
}

int Read(int fd, void *buf, int size)
{
    struct message msg;
    struct reply reply;

    init_lib();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use) return ERROR;

    msg.type = MSG_READ;
    msg.cwd_inum = cwd_inum;
    msg.inum = fd_table[fd].inum;
    msg.reuse = fd_table[fd].reuse;
    msg.position = fd_table[fd].position;
    msg.size = size;
    msg.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) < 0) return ERROR;
    if (Receive(&reply) < 0) return ERROR;

    if (reply.result >= 0) {
        fd_table[fd].position += reply.result;
    }

    return reply.result;
}

int Write(int fd, void *buf, int size)
{
    struct message msg;
    struct reply reply;

    init_lib();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use) return ERROR;

    msg.type = MSG_WRITE;
    msg.cwd_inum = cwd_inum;
    msg.inum = fd_table[fd].inum;
    msg.reuse = fd_table[fd].reuse;
    msg.position = fd_table[fd].position;
    msg.size = size;
    msg.ptr1 = buf;

    if (Send(&msg, -FILE_SERVER) < 0) return ERROR;
    if (Receive(&reply) < 0) return ERROR;

    if (reply.result >= 0) {
        fd_table[fd].position += reply.result;
    }

    return reply.result;
}

int Seek(int fd, int offset, int whence)
{
    int new_pos;

    init_lib();

    if (fd < 0 || fd >= MAX_OPEN_FILES || !fd_table[fd].in_use) return ERROR;

    switch (whence) {
        case SEEK_SET:
            new_pos = offset;
            break;
        case SEEK_CUR:
            new_pos = fd_table[fd].position + offset;
            break;
        case SEEK_END:
            new_pos = 0 + offset;
            break;
        default:
            return ERROR;
    }

    if (new_pos < 0) return ERROR;
    fd_table[fd].position = new_pos;
    return new_pos;
}

int Link(char *oldname, char *newname)
{
    (void)oldname;
    (void)newname;
