int Sync(void)
{
    struct message msg;
    struct reply reply;

    init_lib();

    msg.type = MSG_SYNC;
    msg.cwd_inum = cwd_inum;

    if (Send(&msg, -FILE_SERVER) < 0) return ERROR;
    if (Receive(&reply) < 0) return ERROR;

    return reply.result;
}

int Shutdown(void)
{
    struct message msg;
    struct reply reply;

    init_lib();

    msg.type = MSG_SHUTDOWN;
    msg.cwd_inum = cwd_inum;

    if (Send(&msg, -FILE_SERVER) < 0) return ERROR;
    if (Receive(&reply) < 0) return ERROR;

    return reply.result;
}

#include <comp421/yalnix.h>
#include <comp421/filesystem.h>
#include <stdlib.h>
#include <string.h>
#include <stdio.h>

#define MSG_OPEN        1
#define MSG_CLOSE       2
#define MSG_CREATE      3
#define MSG_READ        4
#define MSG_WRITE       5
#define MSG_SEEK        6
#define MSG_LINK        7
#define MSG_UNLINK      8
#define MSG_SYMLINK     9
#define MSG_READLINK    10
#define MSG_MKDIR       11
#define MSG_RMDIR       12
#define MSG_CHDIR       13
#define MSG_STAT        14
#define MSG_SYNC        15
#define MSG_SHUTDOWN    16

struct message {
    int type;
    int cwd_inum;
    int inum;
    int reuse;
    int position;
    int size;
    void *ptr1;
    int int1;
};

struct reply {
    int result;
    int inum;
    int reuse;
    int stat_type;
    int stat_size;
};

#define INODES_PER_BLOCK (BLOCKSIZE / INODESIZE)

typedef struct block_cache {
    int block_num;
    unsigned char data[BLOCKSIZE];
    int dirty;
    int in_use;
    struct block_cache *prev;
    struct block_cache *next;
} BlockCache;

typedef struct inode_cache {
    int inum;
    struct inode data;
    int dirty;
    int in_use;
    struct inode_cache *prev;
    struct inode_cache *next;
} InodeCache;

static struct fs_header fs_header;
static BlockCache block_cache_data[BLOCK_CACHESIZE];
static InodeCache inode_cache_data[INODE_CACHESIZE];
static BlockCache *block_head = NULL;
static BlockCache *block_tail = NULL;
static InodeCache *inode_head = NULL;
static InodeCache *inode_tail = NULL;

static BlockCache *get_block(int bn)
{
    BlockCache *b;
    for (b = block_head; b; b = b->next) {
        if (b->in_use && b->block_num == bn) {
            if (b != block_head) {
                if (b->next) b->next->prev = b->prev;
                if (b->prev) b->prev->next = b->next;
                if (b == block_tail) block_tail = b->prev;
                b->prev = NULL;
                b->next = block_head;
                if (block_head) block_head->prev = b;
                block_head = b;
            }
            return b;
        }
    }

    for (b = block_cache_data; b < block_cache_data + BLOCK_CACHESIZE; b++) {
        if (!b->in_use) {
            b->block_num = bn;
            b->in_use = 1;
            b->dirty = 0;
            ReadSector(bn, b->data);
            if (!block_head) {
                block_head = block_tail = b;
                b->prev = b->next = NULL;
            } else {
                b->prev = NULL;
                b->next = block_head;
                if (block_head) block_head->prev = b;
                block_head = b;
            }
            return b;
        }
    }

    b = block_tail;
    if (b->dirty) WriteSector(b->block_num, b->data);
    b->block_num = bn;
    b->dirty = 0;
    ReadSector(bn, b->data);
    if (block_head != b) {
        if (b->prev) b->prev->next = b->next;
        if (b->next) b->next->prev = b->prev;
        b->prev = NULL;
        b->next = block_head;
        if (block_head) block_head->prev = b;
        block_head = b;
    }
    return b;
}

static struct inode *get_inode(int inum)
{
    InodeCache *ic;
    BlockCache *bc;
    int block_idx, offset;

    if (inum < 1 || inum > fs_header.num_inodes) return NULL;

    for (ic = inode_head; ic; ic = ic->next) {
        if (ic->in_use && ic->inum == inum) {
            if (ic != inode_head) {
                if (ic->next) ic->next->prev = ic->prev;
                if (ic->prev) ic->prev->next = ic->next;
                if (ic == inode_tail) inode_tail = ic->prev;
                ic->prev = NULL;
                ic->next = inode_head;
                if (inode_head) inode_head->prev = ic;
                inode_head = ic;
            }
            return &ic->data;
        }
    }

    for (ic = inode_cache_data; ic < inode_cache_data + INODE_CACHESIZE; ic++) {
        if (!ic->in_use) {
            block_idx = 1 + (inum / INODES_PER_BLOCK);
            offset = (inum % INODES_PER_BLOCK) * INODESIZE;
            bc = get_block(block_idx);
            if (!bc) return NULL;
            memcpy(&ic->data, bc->data + offset, INODESIZE);
            ic->inum = inum;
            ic->in_use = 1;
            ic->dirty = 0;
            if (!inode_head) {
                inode_head = inode_tail = ic;
                ic->prev = ic->next = NULL;
            } else {
                ic->prev = NULL;
                ic->next = inode_head;
                if (inode_head) inode_head->prev = ic;
                inode_head = ic;
            }
            return &ic->data;
        }
    }

    ic = inode_tail;
    if (ic->dirty) {
        block_idx = 1 + (ic->inum / INODES_PER_BLOCK);
        offset = (ic->inum % INODES_PER_BLOCK) * INODESIZE;
        bc = get_block(block_idx);
        if (bc) {
            memcpy(bc->data + offset, &ic->data, INODESIZE);
            bc->dirty = 1;
        }
    }

    block_idx = 1 + (inum / INODES_PER_BLOCK);
    offset = (inum % INODES_PER_BLOCK) * INODESIZE;
    bc = get_block(block_idx);
    if (!bc) return NULL;
    memcpy(&ic->data, bc->data + offset, INODESIZE);
    ic->inum = inum;
    ic->dirty = 0;
    if (inode_head != ic) {
        if (ic->prev) ic->prev->next = ic->next;
        if (ic->next) ic->next->prev = ic->prev;
        ic->prev = NULL;
        ic->next = inode_head;
        if (inode_head) inode_head->prev = ic;
        inode_head = ic;
    }
    return &ic->data;
}

static void mark_inode_dirty(int inum)
{
    InodeCache *ic;
    for (ic = inode_head; ic; ic = ic->next) {
        if (ic->in_use && ic->inum == inum) {
            ic->dirty = 1;
            return;
        }
    }
}

static int allocate_data_block(void)
{
    static int next_block = -1;
    int first_data, i;

    if (next_block < 0) {
        first_data = 1 + ((fs_header.num_inodes + INODES_PER_BLOCK) / INODES_PER_BLOCK);
        next_block = first_data;
    }

    for (i = next_block; i < fs_header.num_blocks; i++) {
        next_block = i + 1;
        return i;
    }
    return 0;
}

static int write_to_file(int sender_pid, int inum, int position, int size, void *buf_ptr)
{
    struct inode *inode = get_inode(inum);
    int block_idx, offset, to_write, written = 0;
    int block_num;
    BlockCache *block;
    unsigned int *indirect_block;
    unsigned char *data_buf;

    if (!inode) return ERROR;

    data_buf = (unsigned char *)malloc(size);
    if (!data_buf) return ERROR;

    CopyFrom(sender_pid, (void *)data_buf, buf_ptr, size);

    while (written < size) {
        block_idx = (position + written) / BLOCKSIZE;
        offset = (position + written) % BLOCKSIZE;
        to_write = BLOCKSIZE - offset;
        if (to_write > size - written) to_write = size - written;

        if (block_idx < NUM_DIRECT) {
            block_num = inode->direct[block_idx];
            if (block_num == 0) {
                block_num = allocate_data_block();
                if (!block_num) {
                    free(data_buf);
                    return written;
                }
                inode->direct[block_idx] = block_num;
            }
        } else {
            if (inode->indirect == 0) {
                inode->indirect = allocate_data_block();
                if (!inode->indirect) {
                    free(data_buf);
                    return written;
                }
            }
            block = get_block(inode->indirect);
            if (!block) {
                free(data_buf);
                return written;
            }
            indirect_block = (unsigned int *)(block->data);
            block_num = indirect_block[block_idx - NUM_DIRECT];
            if (block_num == 0) {
                block_num = allocate_data_block();
                if (!block_num) {
                    free(data_buf);
                    return written;
                }
                indirect_block[block_idx - NUM_DIRECT] = block_num;
                block->dirty = 1;
            }
        }

        block = get_block(block_num);
        if (!block) {
            free(data_buf);
            return written;
        }

        memcpy(block->data + offset, data_buf + written, to_write);
        block->dirty = 1;
        written += to_write;
    }

    if (position + written > inode->size) {
        inode->size = position + written;
    }
    mark_inode_dirty(inum);
    free(data_buf);
    return written;
}

static int read_from_file(int sender_pid, int inum, int position, int size, void *buf_ptr)
{
    struct inode *inode = get_inode(inum);
    int block_idx, offset, to_read, read_count = 0;
    int block_num;
    BlockCache *block;
    unsigned int *indirect_block;
    unsigned char *data_buf;
    int max_read;

    if (!inode) return ERROR;

    data_buf = (unsigned char *)malloc(size);
    if (!data_buf) return ERROR;

    max_read = inode->size - position;
    if (max_read < 0) max_read = 0;
    if (max_read > size) max_read = size;

    while (read_count < max_read) {
        block_idx = (position + read_count) / BLOCKSIZE;
        offset = (position + read_count) % BLOCKSIZE;
        to_read = BLOCKSIZE - offset;
        if (to_read > max_read - read_count) to_read = max_read - read_count;

        if (block_idx < NUM_DIRECT) {
            block_num = inode->direct[block_idx];
        } else {
            if (inode->indirect == 0) break;
            block = get_block(inode->indirect);
            if (!block) break;
            indirect_block = (unsigned int *)(block->data);
            block_num = indirect_block[block_idx - NUM_DIRECT];
        }

        if (block_num == 0) {
            memset(data_buf + read_count, 0, to_read);
        } else {
            block = get_block(block_num);
            if (!block) break;
            memcpy(data_buf + read_count, block->data + offset, to_read);
        }
        read_count += to_read;
    }

    CopyTo(sender_pid, buf_ptr, (void *)data_buf, read_count);
    free(data_buf);
    return read_count;
}

int main(int argc, char **argv)
{
    int sender_pid;
    struct message msg;
    struct reply reply;
    int child_pid;
    unsigned char sector_buf[BLOCKSIZE];
    struct fs_header *header;

    memset(block_cache_data, 0, sizeof(block_cache_data));
    memset(inode_cache_data, 0, sizeof(inode_cache_data));

    ReadSector(1, sector_buf);
    header = (struct fs_header *)sector_buf;
    fs_header.num_blocks = header->num_blocks;
    fs_header.num_inodes = header->num_inodes;

    Register(FILE_SERVER);

    if (argc > 1) {
        child_pid = Fork();
        if (child_pid == 0) {
            Exec(argv[1], argv + 1);
        }
    }

    while (1) {
        sender_pid = Receive(&msg);

        if (sender_pid == 0) break;
        if (sender_pid == ERROR) continue;

        memset(&reply, 0, sizeof(reply));
        reply.result = ERROR;

        switch (msg.type) {
            case MSG_CREATE: {
                int inum;
                struct inode *inode;
                char pathname[MAXPATHNAMELEN];

                CopyFrom(sender_pid, pathname, msg.ptr1, msg.int1);
                pathname[msg.int1 - 1] = '\0';

                for (inum = 1; inum <= fs_header.num_inodes; inum++) {
                    inode = get_inode(inum);
                    if (inode && inode->type == INODE_FREE) {
                        inode->type = INODE_REGULAR;
                        inode->nlink = 1;
                        inode->size = 0;
                        inode->reuse++;
                        memset(inode->direct, 0, sizeof(inode->direct));
                        inode->indirect = 0;
                        mark_inode_dirty(inum);
                        reply.result = inum;
                        reply.inum = inum;
                        reply.reuse = inode->reuse;
                        break;
                    }
                }
                break;
            }
            case MSG_WRITE: {
                reply.result = write_to_file(sender_pid, msg.inum, msg.position, msg.size, msg.ptr1);
                break;
            }
            case MSG_READ: {
                reply.result = read_from_file(sender_pid, msg.inum, msg.position, msg.size, msg.ptr1);
                break;
            }
            case MSG_SEEK:
                reply.result = msg.position;
                break;
            case MSG_SYNC:
            case MSG_MKDIR:
            case MSG_RMDIR:
            case MSG_CHDIR:
            case MSG_STAT:
            case MSG_OPEN:
            case MSG_CLOSE:
                reply.result = 0;
                break;
            case MSG_SHUTDOWN:
                reply.result = 0;
                Reply(&reply, sender_pid);
                Exit(0);
                break;
            default:
                break;
        }

        Reply(&reply, sender_pid);
    }

    return 0;
}

